#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdbool.h>
#define MAXN 200005
#define INF 0x3f3f3f3f
#define MOD 1000000007
#define ll long long
#define db double
#define pii pair<int, int>
typedef struct Node{
    int to;
    struct Node* next;
}Node;
Node* head[MAXN];
int n, m, k, t;
int a[MAXN];
int oddness[MAXN];
int beauty[MAXN];
void addEdge(int u, int v) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->to = v;
    newNode->next = head[u];
    head[u] = newNode;
}
void bfs(int u) {
    int queue[MAXN];
    int front = 0, rear = 0;
    queue[rear++] = u;
    int visited[MAXN] = {0};
    visited[u] = 1;
    while (front < rear) {
        int v = queue[front++];
        Node* p = head[v];
        while (p) {
            if (!visited[p->to]) {
                queue[rear++] = p->to;
                visited[p->to] = 1;
            }
            p = p->next;
        }
    }
    for (int i = 1; i <= n; i++) {
        if (visited[i]) {
            oddness[i]++;
        }
    }
}
int main() {
    scanf("%d", &t);
    while (t--) {
        scanf("%d", &n);
        for (int i = 1; i <= n; i++) {
            scanf("%d", &a[i]);
            addEdge(i, a[i]);
            addEdge(a[i], i);
        }
        for (int i = 1; i <= n; i++) {
            bfs(i);
            beauty[i] = 0;
            for (int j = 1; j <= n; j++) {
                beauty[i] = max(beauty[i], oddness[j]);
            }
        }
        int ans = 0;
        for (int i = 1; i <= n; i++) {
            ans += beauty[i];
        }
        printf("%d\n", ans);
    }
    return 0;
}

